import React, { useState, useRef, useEffect } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';

const NOTIFICATIONS = [
  {
    id: 1,
    icon: '❤️',
    title: 'Heart Rate Normal',
    desc: 'Resting heart rate is 72 bpm — healthy range.',
    time: '2 min ago',
    type: 'good',
  },
  {
    id: 2,
    icon: '😴',
    title: 'Sleep Goal Not Met',
    desc: 'You slept 5.5 hrs last night. Aim for 8 hrs.',
    time: '1 hr ago',
    type: 'warn',
  },
  {
    id: 3,
    icon: '🔥',
    title: 'Calorie Goal Almost Reached',
    desc: "You're at 72% of your daily calorie burn goal.",
    time: '3 hr ago',
    type: 'info',
  },
  {
    id: 4,
    icon: '🧠',
    title: 'Stress Level Elevated',
    desc: 'HRV indicates moderate stress. Consider a short walk.',
    time: '5 hr ago',
    type: 'warn',
  },
];

const typeColor = {
  good: { dot: '#34d399', bg: 'rgba(52,211,153,0.08)', border: 'rgba(52,211,153,0.18)' },
  warn: { dot: '#fbbf24', bg: 'rgba(251,191,36,0.08)', border: 'rgba(251,191,36,0.18)' },
  info: { dot: '#60a5fa', bg: 'rgba(96,165,250,0.08)', border: 'rgba(96,165,250,0.18)' },
};

const Layout = ({ children, stats = { xp: 0, coins: 0 } }) => {
  const location = useLocation();
  const navigate = useNavigate();
  const [notifOpen, setNotifOpen] = useState(false);
  const [read, setRead] = useState({});
  const notifRef = useRef(null);

  const unreadCount = NOTIFICATIONS.filter(n => !read[n.id]).length;

  // Close on outside click
  useEffect(() => {
    const handler = (e) => {
      if (notifRef.current && !notifRef.current.contains(e.target)) {
        setNotifOpen(false);
      }
    };
    document.addEventListener('mousedown', handler);
    return () => document.removeEventListener('mousedown', handler);
  }, []);

  const handleViewAll = () => {
    // Mark all as read
    const allRead = Object.fromEntries(NOTIFICATIONS.map(n => [n.id, true]));
    setRead(allRead);
    setNotifOpen(false);
    navigate('/notifications');
  };

  const handleNotifClick = (id) => {
    setRead(prev => ({ ...prev, [id]: true }));
  };

  const menuItems = [
    { path: '/',              icon: '/dashboard.png',          label: 'Dashboard' },
    { path: '/program',       icon: '/user.png',               label: 'Program and Avatar customization' },
    { path: '/challenges',    icon: '/rpg-game.png',           label: 'Challenges' },
    { path: '/goals',         icon: '/dart.png',               label: 'Goals and Progress' },
    { path: '/activity-food', icon: '/healthy-food.png',       label: 'Daily Health Log' },
    { path: '/notifications', icon: '/notification-bell.png',  label: 'Notifications and Report' },
    { path: '/chatbot',       icon: '/robot (1).png',          label: 'Chatbot' },
  ];

  return (
    <div>
      {/* ── Top Navigation Bar ── */}
      <header className="topbar">

        {/* Left: Logo + Brand */}
        <div className="topbar-left">
          <img src="/logo-transparent.png" alt="Logo" className="topbar-logo" />
          <span className="topbar-brand">HealUp!</span>
        </div>

        {/* Centre: Icon buttons */}
        <div className="topbar-center">
          <button className="topbar-icon-btn" onClick={() => navigate('/chatbot')} title="AI Chatbot">
            <img src="/robot.png" alt="Chatbot" className="topbar-icon-img" />
          </button>
          <button className="topbar-icon-btn" title="Sync Devices">
            <img src="/fitness-tracker.png" alt="Sync" className="topbar-icon-img" />
          </button>

          {/* ── Notification Bell ── */}
          <div ref={notifRef} style={{ position: 'relative' }}>
            <button
              className="topbar-icon-btn"
              title="Alerts"
              onClick={() => setNotifOpen(prev => !prev)}
              style={{ position: 'relative' }}
            >
              <img src="/notification.png" alt="Alerts" className="topbar-icon-img" />
              {unreadCount > 0 && (
                <span style={{
                  position: 'absolute',
                  top: 2, right: 2,
                  width: 16, height: 16,
                  background: '#ef4444',
                  borderRadius: '50%',
                  fontSize: '0.6rem',
                  fontWeight: 800,
                  color: '#fff',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  border: '2px solid #0b1a27',
                  lineHeight: 1,
                  pointerEvents: 'none',
                }}>
                  {unreadCount}
                </span>
              )}
            </button>

            {/* ── Dropdown Panel ── */}
            {notifOpen && (
              <div style={{
                position: 'absolute',
                top: 'calc(100% + 10px)',
                right: '-60px',
                width: 320,
                background: 'linear-gradient(135deg, #0e2236, #1a3a52)',
                border: '1px solid rgba(91,184,255,0.2)',
                borderRadius: 20,
                boxShadow: '0 20px 60px rgba(0,0,0,0.6), 0 0 0 1px rgba(91,184,255,0.05)',
                zIndex: 9999,
                overflow: 'hidden',
                animation: 'notifDropIn 0.22s cubic-bezier(0.34,1.56,0.64,1)',
              }}>

                {/* Header */}
                <div style={{
                  display: 'flex', alignItems: 'center', justifyContent: 'space-between',
                  padding: '1rem 1.2rem 0.75rem',
                  borderBottom: '1px solid rgba(91,184,255,0.1)',
                }}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                    <span style={{ fontSize: '1rem' }}>🔔</span>
                    <span style={{ fontWeight: 800, fontSize: '0.88rem', color: '#fff', letterSpacing: '0.03em' }}>
                      Notifications
                    </span>
                    {unreadCount > 0 && (
                      <span style={{
                        background: 'rgba(239,68,68,0.2)', color: '#f87171',
                        border: '1px solid rgba(239,68,68,0.3)',
                        fontSize: '0.6rem', fontWeight: 800,
                        padding: '1px 7px', borderRadius: 20,
                      }}>
                        {unreadCount} new
                      </span>
                    )}
                  </div>
                  <button
                    onClick={() => {
                      const allRead = Object.fromEntries(NOTIFICATIONS.map(n => [n.id, true]));
                      setRead(allRead);
                    }}
                    style={{
                      background: 'none', border: 'none', color: '#5a88a8',
                      fontSize: '0.68rem', fontWeight: 700, cursor: 'pointer',
                      letterSpacing: '0.04em',
                    }}
                  >
                    Mark all read
                  </button>
                </div>

                {/* Notification list */}
                <div style={{ maxHeight: 260, overflowY: 'auto', padding: '0.5rem 0.6rem' }}>
                  {NOTIFICATIONS.map(n => {
                    const c = typeColor[n.type];
                    const isRead = !!read[n.id];
                    return (
                      <div
                        key={n.id}
                        onClick={() => handleNotifClick(n.id)}
                        style={{
                          display: 'flex', gap: '0.7rem', alignItems: 'flex-start',
                          padding: '0.65rem 0.7rem',
                          borderRadius: 12,
                          background: isRead ? 'transparent' : c.bg,
                          border: `1px solid ${isRead ? 'transparent' : c.border}`,
                          marginBottom: '0.35rem',
                          cursor: 'pointer',
                          transition: 'all 0.15s',
                          opacity: isRead ? 0.55 : 1,
                        }}
                      >
                        {/* Coloured dot */}
                        <div style={{
                          width: 8, height: 8, borderRadius: '50%',
                          background: isRead ? '#334155' : c.dot,
                          boxShadow: isRead ? 'none' : `0 0 6px ${c.dot}`,
                          flexShrink: 0, marginTop: 5,
                        }} />
                        <div style={{ flex: 1, minWidth: 0 }}>
                          <div style={{ display: 'flex', alignItems: 'center', gap: '0.4rem', marginBottom: 2 }}>
                            <span style={{ fontSize: '0.85rem' }}>{n.icon}</span>
                            <span style={{ fontSize: '0.78rem', fontWeight: 700, color: '#e2e8f0' }}>{n.title}</span>
                          </div>
                          <div style={{ fontSize: '0.7rem', color: '#5a88a8', lineHeight: 1.4 }}>{n.desc}</div>
                          <div style={{ fontSize: '0.62rem', color: '#3d6b8a', marginTop: 3 }}>{n.time}</div>
                        </div>
                      </div>
                    );
                  })}
                </div>

                {/* Footer: View All */}
                <div style={{
                  padding: '0.75rem 1rem',
                  borderTop: '1px solid rgba(91,184,255,0.1)',
                }}>
                  <button
                    onClick={handleViewAll}
                    style={{
                      width: '100%',
                      padding: '0.6rem',
                      background: 'linear-gradient(135deg, rgba(91,184,255,0.15), rgba(91,184,255,0.08))',
                      border: '1px solid rgba(91,184,255,0.3)',
                      borderRadius: 12,
                      color: '#5bb8ff',
                      fontWeight: 800,
                      fontSize: '0.8rem',
                      cursor: 'pointer',
                      letterSpacing: '0.05em',
                      transition: 'all 0.15s',
                    }}
                    onMouseEnter={e => e.currentTarget.style.background = 'rgba(91,184,255,0.22)'}
                    onMouseLeave={e => e.currentTarget.style.background = 'linear-gradient(135deg, rgba(91,184,255,0.15), rgba(91,184,255,0.08))'}
                  >
                    View All Notifications →
                  </button>
                </div>

              </div>
            )}
          </div>
          {/* ── End Notification Bell ── */}

        </div>

        {/* Right: XP + Coins + Profile */}
        <div className="topbar-right">
          <div className="topbar-stat-chip xp-chip">
            <img src="/star.png" alt="XP" className="topbar-stat-icon-img" />
            <span className="topbar-stat-value">{stats.xp.toLocaleString()}</span>
            <span className="topbar-stat-label">XP</span>
          </div>
          <div className="topbar-stat-chip coins-chip">
            <img src="/profit.png" alt="Coins" className="topbar-stat-icon-img" />
            <span className="topbar-stat-value">{stats.coins.toLocaleString()}</span>
            <span className="topbar-stat-label">Coins</span>
          </div>
          <div className="topbar-avatar-chip">
            <div className="topbar-avatar-dot" />
            <span className="topbar-avatar-name">My Profile</span>
          </div>
        </div>

      </header>

      {/* ── Sidebar + Content ── */}
      <div className="layout-container">
        <aside className="sidebar">
          <nav className="sidebar-nav">
            {menuItems.map((item) => (
              <Link
                key={item.path}
                to={item.path}
                className={`sidebar-item ${location.pathname === item.path ? 'active' : ''}`}
                data-testid={`nav-${item.label.toLowerCase().replace(/\s+/g, '-')}`}
              >
                <img src={item.icon} alt={item.label} className="sidebar-icon-img" />
                <span className="sidebar-label">{item.label}</span>
              </Link>
            ))}
          </nav>
        </aside>

        <main className="main-content">
          {children}
        </main>
      </div>

      {/* ── Notif dropdown animation ── */}
      <style>{`
        @keyframes notifDropIn {
          from { opacity: 0; transform: translateY(-8px) scale(0.96); }
          to   { opacity: 1; transform: translateY(0)    scale(1); }
        }
      `}</style>
    </div>
  );
};

export default Layout;
